-- Fix donor_contacts: rename donorName->name, platform->donorPlatform (enum), donationAmount->amountUSD, status->donorStatus
-- Step 1: Change status to varchar first
ALTER TABLE `donor_contacts` CHANGE COLUMN `status` `status` VARCHAR(50) NOT NULL DEFAULT 'new';
-- Step 2: Update status values to match new enum
UPDATE `donor_contacts` SET `status` = 'new' WHERE `status` IN ('Pending', 'pending');
UPDATE `donor_contacts` SET `status` = 'thanked' WHERE `status` = 'Sent';
UPDATE `donor_contacts` SET `status` = 'responded' WHERE `status` = 'Responded';
UPDATE `donor_contacts` SET `status` = 'no_reply' WHERE `status` = 'Archived';
-- Step 3: Rename donorName -> name
ALTER TABLE `donor_contacts` CHANGE COLUMN `donorName` `name` VARCHAR(255) NOT NULL;
-- Step 4: Rename platform -> donorPlatform with correct enum
ALTER TABLE `donor_contacts` CHANGE COLUMN `platform` `donorPlatform` ENUM('kofi','buymeacoffee','grant','individual','other') NOT NULL DEFAULT 'individual';
-- Step 5: Rename donationAmount -> amountUSD
ALTER TABLE `donor_contacts` CHANGE COLUMN `donationAmount` `amountUSD` VARCHAR(50) NULL;
-- Step 6: Rename status -> donorStatus with correct enum
ALTER TABLE `donor_contacts` CHANGE COLUMN `status` `donorStatus` ENUM('new','thanked','follow_up_sent','responded','declined','no_reply') NOT NULL DEFAULT 'new';
-- Step 7: Add missing columns
ALTER TABLE `donor_contacts`
  ADD COLUMN IF NOT EXISTS `handle` VARCHAR(255) NULL,
  ADD COLUMN IF NOT EXISTS `tier` VARCHAR(100) NULL,
  ADD COLUMN IF NOT EXISTS `lastContactedAt` TIMESTAMP NULL,
  ADD COLUMN IF NOT EXISTS `followUpDate` TIMESTAMP NULL,
  ADD COLUMN IF NOT EXISTS `replyNotes` TEXT NULL,
  ADD COLUMN IF NOT EXISTS `replyReceivedAt` TIMESTAMP NULL,
  ADD COLUMN IF NOT EXISTS `internalNotes` TEXT NULL,
  ADD COLUMN IF NOT EXISTS `grantOrg` VARCHAR(255) NULL,
  ADD COLUMN IF NOT EXISTS `grantDeadline` VARCHAR(10) NULL,
  ADD COLUMN IF NOT EXISTS `grantAmount` VARCHAR(100) NULL,
  ADD COLUMN IF NOT EXISTS `grantUrl` VARCHAR(1000) NULL;
-- Step 8: Remove columns that don't exist in original schema
ALTER TABLE `donor_contacts`
  DROP COLUMN IF EXISTS `territory`,
  DROP COLUMN IF EXISTS `lastTemplateUsed`;

